  ('optometrist-moex-00884', 'optometrist', 'optometrist-moex-111-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '方先生目前戴-7.50DS眼鏡，若他想配戴隱形眼鏡，學理上的隱形眼鏡度數為何？（假設頂點距離為12mm）', '["-8.25DS", "-7.50DS", "-7.17DS", "-6.88DS"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:44+00:00", "source_pdf_sha1": "87ef5245a224", "answer_pdf_sha1": "ba5822650940", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "111", "s": "1003", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
